const crypto = require('crypto');
const config = $('Configuration (EDIT ME)').first().json;
const item = $input.first();

const header = (item.json.headers && item.json.headers['x-sellf-signature']) || '';
const rawBody = item.binary && item.binary.data
  ? Buffer.from(item.binary.data.data, 'base64').toString('utf8')
  : JSON.stringify(item.json.body || {});

// Header format (Stripe/Svix style): t=<unix>,v1=<hex>[,v1=<hex2 during secret rotation>]
let t = null;
const sigs = [];
for (const part of header.split(',')) {
  const eq = part.indexOf('=');
  if (eq === -1) continue;
  const key = part.slice(0, eq).trim();
  const value = part.slice(eq + 1).trim();
  if (key === 't') t = value;
  else if (key === 'v1') sigs.push(value);
}

let valid = false;
if (t && sigs.length && config.webhookSecret) {
  const expected = crypto.createHmac('sha256', config.webhookSecret).update(`${t}.${rawBody}`).digest('hex');
  const withinTolerance = Math.abs(Math.floor(Date.now() / 1000) - Number(t)) <= 300;
  valid = withinTolerance && sigs.some((v1) =>
    v1.length === expected.length && crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(v1)));
}

return [{ json: { valid, body: JSON.parse(rawBody) } }];

const body = $input.first().json.body;
const d = body.data;

const email = (d.customer && d.customer.email) || d.email;
if (!email) throw new Error('lead.captured payload has no email');
const firstName = (d.customer && d.customer.firstName) || '';

return [{ json: {
  email,
  firstName,
  name: d.customer ? [d.customer.firstName, d.customer.lastName].filter(Boolean).join(' ') : '',
  productName: (d.product && d.product.name) || '',
  productId: (d.product && d.product.id) || '',
} }];
